-- Enable the trigram extension (run once, requires superuser):
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- Create a GIN index on the name column for trigram search:
CREATE INDEX products_name_trgm_idx ON products USING GIN(name gin_trgm_ops);

-- Now the LIKE query uses the index:
SELECT id, name, price
FROM products
WHERE name ILIKE '%laptop%';

SELECT id, name, price
FROM products
WHERE name LIKE 'laptop%';

-- Create a GIN full-text index:
CREATE INDEX products_name_fts_idx ON products USING GIN(to_tsvector('english', name));

SELECT id, name, price
FROM products
WHERE to_tsvector('english', name) @@ to_tsquery('english', 'laptop');
